import{_ as t,o as e,c as n,ae as a}from"./chunks/framework.BXqLssiy.js";const p=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md"}'),i={name:"guide/introduction.md"};function r(s,o,l,c,d,u){return e(),n("div",null,[...o[0]||(o[0]=[a('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>NanoBoot is a lightweight Spring Boot-like micro-framework designed for Java development. It provides essential features like dependency injection, web development, data access, and WebSocket support in a modular, easy-to-use package.</p><h2 id="what-is-nanoboot" tabindex="-1">What is NanoBoot? <a class="header-anchor" href="#what-is-nanoboot" aria-label="Permalink to &quot;What is NanoBoot?&quot;">​</a></h2><p>NanoBoot is a Java framework that takes inspiration from Spring Boot but with a focus on being more lightweight and modular. It provides the core features developers need for building modern Java applications without the overhead of a full Spring ecosystem.</p><h3 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h3><ul><li><strong>Dependency Injection Container</strong>: Automatic wiring of components with <code>@Autowired</code></li><li><strong>Annotation Processing</strong>: Support for <code>@Component</code>, <code>@Service</code>, <code>@Controller</code>, and more</li><li><strong>Web Framework</strong>: Built-in HTTP server with routing and REST API support</li><li><strong>Data Access</strong>: Database connections and Redis integration</li><li><strong>WebSocket Support</strong>: Real-time communication capabilities</li><li><strong>CLI Tool</strong>: Command-line interface to generate projects quickly</li><li><strong>Externalized Configuration</strong>: Property-based configuration management</li></ul><h3 id="why-choose-nanoboot" tabindex="-1">Why Choose NanoBoot? <a class="header-anchor" href="#why-choose-nanoboot" aria-label="Permalink to &quot;Why Choose NanoBoot?&quot;">​</a></h3><ul><li><strong>Lightweight</strong>: Smaller footprint than Spring Boot</li><li><strong>Familiar</strong>: Uses similar annotations and patterns as Spring</li><li><strong>Modular</strong>: Choose only the components you need</li><li><strong>Fast Startup</strong>: Quicker application boot times</li><li><strong>Easy Learning Curve</strong>: If you know Spring, you know NanoBoot</li></ul><h3 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h3><p>NanoBoot is built with a modular architecture:</p><ul><li><strong>nano-boot-core</strong>: Core dependency injection container</li><li><strong>nano-boot-starter</strong>: Application bootstrap and annotation processing</li><li><strong>nano-boot-web</strong>: Web server and HTTP routing</li><li><strong>nano-boot-data</strong>: Data access layer with database and Redis support</li><li><strong>nano-boot-websocket</strong>: WebSocket communication</li><li><strong>nano-boot-cli</strong>: Command-line interface for project generation</li></ul><p>Each module can be used independently or combined to create a full-featured application.</p>',12)])])}const h=t(i,[["render",r]]);export{p as __pageData,h as default};
